SELECT 
FROM project_task t
LEFT JOIN project p ON p.id = t.project_id AND p.deleted = 0
LEFT JOIN project_phase ph ON ph.id = t.phase_id AND ph.deleted = 0
LEFT JOIN sys_user u ON u.id = t.assignee_id AND u.deleted = 0
LEFT JOIN agent_company ac ON ac.id = t.agent_company_id AND ac.deleted = 0

    t.deleted = 0

        AND t.project_id = #{query.projectId}


        AND t.phase_id = #{query.phaseId}


        AND t.parent_task_id = #{query.parentTaskId}


        AND t.parent_task_id IS NULL


        AND t.task_name LIKE CONCAT('%', #{query.keyword}, '%')


        AND t.status = #{query.status}


        AND t.assignee_id = #{query.assigneeId}


        AND t.agent_company_id = #{query.agentCompanyId}


        AND t.agent_engineer_id = #{query.agentEngineerId}


        AND t.execute_mode = #{query.executeMode}


        AND t.task_type = #{query.taskType}


ORDER BY t.create_time DESC
